1	import { ensureSchema } from "./schema.mjs";
2	
3	function rowToAccount(r) {
4	  return { accountId: r.account_id, name: r.name, tier: r.tier, status: r.status, createdAt: r.created_at };
5	}
6	
7	export async function createAccounts(client, data) {
8	  await ensureSchema(client);
9	  const result = await client.query(
10	    'INSERT INTO accounts (account_id, name, tier, status, created_at) VALUES ($1, $2, $3, $4, $5) RETURNING *',
11	    [data.accountId, data.name, data.tier, data.status, data.createdAt || new Date()]
12	  );
13	  return rowToAccount(result.rows[0]);
14	}
15	
16	export async function getAccounts(client, id) {
17	  const res = await client.query('SELECT * FROM accounts WHERE account_id = $1', [id]);
18	  return res.rows[0] ? rowToAccount(res.rows[0]) : null;
19	}
