21	export async function updateAccounts(client, id, data) {
22	  const sets = [];
23	  const vals = [];
24	  let i = 1;
25	  if (data.name !== undefined) { sets.push(`name = $${i++}`); vals.push(data.name); }
26	  if (data.tier !== undefined) { sets.push(`tier = $${i++}`); vals.push(data.tier); }
27	  if (data.status !== undefined) { sets.push(`status = $${i++}`); vals.push(data.status); }
28	  if (sets.length === 0) return getAccounts(client, id);
29	  vals.push(id);
30	  await client.query(`UPDATE accounts SET ${sets.join(', ')} WHERE account_id = $${i}`, vals);
31	  return getAccounts(client, id);
32	}
33	
34	export async function deleteAccounts(client, id) {
35	  const res = await client.query('DELETE FROM accounts WHERE account_id = $1', [id]);
36	  return res.rowCount > 0;
37	}
