6	await withDb(async (client) => {
7	  await ensureSchema(client);
8	
9	  // === REGRESSION: existing CRUD still works without riskScore ===
10	  const created = await createAccounts(client, {
11	    accountId: "acct-regression-1",
12	    name: "Regression Test Account",
13	    tier: "strategic",
14	    status: "active",
15	  });
16	  ok(created.accountId, "regression: create returns account with id");
17	
18	  const read = await getAccounts(client, "acct-regression-1");
19	  ok(read, "regression: get returns the account");
20	  strictEqual(read.name, "Regression Test Account", "regression: name matches");
21	
22	  const updated = await updateAccounts(client, "acct-regression-1", { name: "Updated Name" });
23	  strictEqual(updated.name, "Updated Name", "regression: update works");
24	
25	  const deleted = await deleteAccounts(client, "acct-regression-1");
26	  ok(deleted, "regression: delete works");
27	
28	  // === NEW: riskScore field (0-100 integer) ===
29	  const createdWithRisk = await createAccounts(client, {
30	    accountId: "acct-risk-1",
31	    name: "Risk Score Account",
32	    tier: "midmarket",
33	    status: "at-risk",
34	    riskScore: 75,
35	  });
36	  ok(createdWithRisk.riskScore !== undefined, "new: create with riskScore returns it");
37	
38	  // verify riskScore is in the live DB (snake_case column)
39	  const liveRow = (await client.query('SELECT * FROM accounts WHERE account_id = $1', ["acct-risk-1"])).rows[0];
40	  strictEqual(liveRow.risk_score, 75, "new: live DB has risk_score=75");
41	
42	  // get returns riskScore
43	  const readWithRisk = await getAccounts(client, "acct-risk-1");
44	  strictEqual(readWithRisk.riskScore, 75, "new: get returns riskScore");
45	
46	  // update riskScore
47	  const updatedRisk = await updateAccounts(client, "acct-risk-1", { riskScore: 90 });
48	  strictEqual(updatedRisk.riskScore, 90, "new: update riskScore works");
49	
50	  // verify update hit the live DB
51	  const liveUpdated = (await client.query('SELECT * FROM accounts WHERE account_id = $1', ["acct-risk-1"])).rows[0];
52	  strictEqual(liveUpdated.risk_score, 90, "new: live DB reflects riskScore update");
53	
54	  // cleanup
55	  await deleteAccounts(client, "acct-risk-1");
56	});
